"use client";

import React, { use, useState, useEffect } from "react";
import {
  Upload,
  X,
  MapPin,
  Tag,
  Calendar,
  CheckCircle,
  AlertCircle,
  FileText,
  ArrowLeft,
  ChevronLeft,
} from "lucide-react";
import Link from "next/link";

const ClaimItemPage = ({ params }) => {
  const resolvedParams = use(params);
  const { id } = resolvedParams;
  const [loading, setLoading] = useState(true);
  const [item, setItem] = useState(null);

  // States for form and submission
  const [claimText, setClaimText] = useState("");
  const [proofImages, setProofImages] = useState([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  useEffect(() => {
    const fetchItem = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch(`http://localhost:5000/item/details/${id}`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        const newData = await res.json();
        setItem(newData.data || newData);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    if (id) fetchItem();
  }, [id]);

  // ==================== HANDLERS ====================
  const handleFileUpload = (e) => {
    const files = Array.from(e.target.files);
    if (files.length + proofImages.length > 3) {
      alert("Maximum 3 images allowed");
      return;
    }
    const imageFiles = files.filter((file) => file.type.startsWith("image/"));
    setProofImages([...proofImages, ...imageFiles]);
    e.target.value = null;
  };

  const removeImage = (index) => {
    setProofImages(proofImages.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!claimText.trim()) return;

    try {
      setIsSubmitting(true);
      const token = localStorage.getItem("accessToken");
      const formData = new FormData();
      formData.append("claimText", claimText);
      proofImages.forEach((img) => {
        formData.append("proofImages", img);
      });

      const res = await fetch(`http://localhost:5000/report/claimItem/${id}`, {
        method: "POST",
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.message || "Claim failed");
      }

      // Instead of alert, we trigger the success view
      setIsSubmitted(true);
    } catch (err) {
      console.error(err);
      alert(err.message || "Something went wrong");
    } finally {
      setIsSubmitting(false);
    }
  };

  // ==================== LOADING/ERROR STATES ====================
  if (loading)
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="w-10 h-10 border-4 border-indigo-800 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );

  if (!item)
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 px-4">
        <div className="text-center p-12 bg-white rounded-3xl shadow-xl max-w-md border border-gray-100">
          <AlertCircle className="w-20 h-20 text-rose-500 mx-auto mb-6" />
          <h2 className="text-3xl font-bold text-gray-900 mb-2">
            Item Not Found
          </h2>
          <p className="text-gray-600 mb-8">
            This item may have been removed or the link is broken.
          </p>
          <Link
            href="/items"
            className="inline-flex items-center text-indigo-800 font-bold hover:gap-2 transition-all"
          >
            <ChevronLeft size={20} /> Back to Items
          </Link>
        </div>
      </div>
    );

  // ==================== RENDER ====================
  return (
    <div className="min-h-screen bg-[#f9fafb]">
      <div className="max-w-7xl mx-auto py-10 px-4 sm:px-6 lg:px-8">
        {isSubmitted ? (
          /* SUCCESS PAGE VIEW */
          <div className="max-w-2xl mx-auto mt-10 text-center bg-white p-10 md:p-16 rounded-[2.5rem] shadow-sm border border-gray-100">
            <div className="w-24 h-24 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-8 animate-bounce">
              <CheckCircle className="w-12 h-12 text-emerald-600" />
            </div>
            <h2 className="text-4xl font-black text-slate-900 mb-4 tracking-tight">
              Claim Submitted!
            </h2>
            <p className="text-slate-600 mb-10 text-lg leading-relaxed">
              Your claim for <strong>{item.itemName}</strong> is now under
              review. Our team will verify your ownership details and update you
              soon.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              <Link
                href="/dashboard"
                className="px-10 py-4 bg-indigo-800 text-white rounded-2xl font-bold hover:bg-indigo-900 transition-all shadow-lg hover:shadow-indigo-200 active:scale-95"
              >
                Go to Dashboard
              </Link>
              <Link
                href="/items"
                className="px-10 py-4 bg-slate-100 text-slate-700 rounded-2xl font-bold hover:bg-slate-200 transition-all active:scale-95"
              >
                Browse Items
              </Link>
            </div>
          </div>
        ) : (
          /* FORM VIEW */
          <>
            {/* Page Header */}
            <div className="mb-10">
              <Link
                href="/items"
                className="flex items-center text-sm font-bold text-slate-500 hover:text-indigo-800 mb-6 transition-colors group"
              >
                <ArrowLeft
                  size={16}
                  className="mr-2 group-hover:-translate-x-1 transition-transform"
                />{" "}
                Back to Catalog
              </Link>
              <div className="inline-block bg-indigo-100 text-indigo-800 px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest mb-4">
                Claim Verification
              </div>
              <h1 className="text-4xl font-black text-slate-900 tracking-tight">
                Claim: {item.itemName}
              </h1>
            </div>

            <div className="grid lg:grid-cols-3 gap-8">
              {/* LEFT COLUMN - Item Details */}
              <div className="lg:col-span-2 space-y-6">
                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
                  <div className="h-80 md:h-96 bg-slate-100 relative">
                    <img
                      src={
                        item.photos?.[0] ||
                        "https://placehold.co/800x600/4F46E5/FFFFFF?text=Item"
                      }
                      alt={item.itemName}
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute top-6 right-6 bg-white/90 backdrop-blur-md px-4 py-2 rounded-xl text-sm font-black text-indigo-800 shadow-xl">
                      {item.category}
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8">
                  <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-3">
                    <FileText className="w-6 h-6 text-indigo-800" />
                    Official Item Log
                  </h3>
                  <div className="mb-8 p-6 bg-slate-50 rounded-2xl border border-slate-100 italic text-slate-600">
                    "{item.description}"
                  </div>
                  <div className="grid sm:grid-cols-3 gap-4">
                    <InfoCard
                      icon={Tag}
                      label="Category"
                      value={item.category}
                    />
                    <InfoCard
                      icon={MapPin}
                      label="Found At"
                      value={item.location}
                    />
                    <InfoCard
                      icon={Calendar}
                      label="Log Date"
                      value={item.date}
                    />
                  </div>
                </div>
              </div>

              {/* RIGHT COLUMN - Claim Form */}
              <div className="lg:col-span-1">
                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8 sticky top-8">
                  <h2 className="text-2xl font-black text-slate-900 mb-6">
                    Your Proof
                  </h2>
                  <form onSubmit={handleSubmit} className="space-y-6">
                    <div>
                      <label
                        htmlFor="claimText"
                        className="block text-sm font-black text-slate-400 uppercase tracking-widest mb-3"
                      >
                        Ownership Details{" "}
                        <span className="text-rose-500">*</span>
                      </label>
                      <textarea
                        id="claimText"
                        rows={5}
                        value={claimText}
                        onChange={(e) => setClaimText(e.target.value)}
                        className="w-full border border-slate-200 rounded-2xl p-4 text-sm focus:outline-none focus:border-indigo-800 focus:ring-4 focus:ring-indigo-50 transition-all resize-none"
                        placeholder="Provide details only the owner would know (e.g. brand, scratches, content inside)..."
                        required
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-black text-slate-400 uppercase tracking-widest mb-3">
                        Photos ({proofImages.length}/3)
                      </label>
                      <div className="relative group">
                        <input
                          type="file"
                          multiple
                          accept="image/*"
                          onChange={handleFileUpload}
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10 disabled:cursor-not-allowed"
                          disabled={proofImages.length >= 3}
                        />
                        <div
                          className={`border-2 border-dashed rounded-2xl p-8 text-center transition-all ${
                            proofImages.length >= 3
                              ? "border-slate-100 bg-slate-50"
                              : "border-slate-200 bg-white group-hover:border-indigo-400"
                          }`}
                        >
                          <Upload
                            className={`w-8 h-8 mx-auto mb-3 ${proofImages.length >= 3 ? "text-slate-300" : "text-indigo-600"}`}
                          />
                          <p className="text-xs font-bold text-slate-700">
                            Add supporting images
                          </p>
                        </div>
                      </div>

                      {proofImages.length > 0 && (
                        <div className="grid grid-cols-3 gap-3 mt-4">
                          {proofImages.map((file, idx) => (
                            <div
                              key={idx}
                              className="relative aspect-square rounded-xl overflow-hidden border border-slate-200 group"
                            >
                              <img
                                src={URL.createObjectURL(file)}
                                alt="Proof"
                                className="w-full h-full object-cover"
                              />
                              <button
                                type="button"
                                onClick={() => removeImage(idx)}
                                className="absolute top-1 right-1 bg-rose-500 text-white p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-all hover:scale-110 shadow-lg"
                              >
                                <X size={14} />
                              </button>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>

                    <div className="bg-indigo-50 rounded-2xl p-4 flex gap-3 items-start">
                      <AlertCircle className="w-5 h-5 text-indigo-600 shrink-0 mt-0.5" />
                      <p className="text-xs text-indigo-900/70 font-medium leading-relaxed">
                        Fraudulent claims are a violation of policy. Please
                        ensure your information is accurate.
                      </p>
                    </div>

                    <button
                      type="submit"
                      disabled={isSubmitting || !claimText.trim()}
                      className="w-full bg-indigo-800 text-white py-4 rounded-2xl font-black text-sm hover:bg-indigo-900 transition-all shadow-xl hover:shadow-indigo-100 active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-3"
                    >
                      {isSubmitting ? (
                        <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                      ) : (
                        <CheckCircle size={18} />
                      )}
                      {isSubmitting ? "Processing..." : "Submit Claim"}
                    </button>
                  </form>
                </div>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

// Helper component for info cards
function InfoCard({ icon: Icon, label, value }) {
  return (
    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
      <div className="flex items-center gap-2 mb-1">
        <Icon size={14} className="text-indigo-600" />
        <p className="text-[10px] font-black uppercase tracking-tighter text-slate-400">
          {label}
        </p>
      </div>
      <p className="text-sm font-bold text-slate-800 truncate">{value}</p>
    </div>
  );
}

export default ClaimItemPage;
